import json
import re
from collections import Counter

# Get Europe metadata for 2010-2020
metadata_key = 'var_functions.query_db:2'
metadata_data = locals()[metadata_key]

if isinstance(metadata_data, str) and metadata_data.endswith('.json'):
    with open(metadata_data, 'r') as f:
        metadata_data = json.load(f)

# Group by year
europe_ids_by_year = {}
for meta in metadata_data:
    year = int(meta['publication_date'][:4])
    if 2010 <= year <= 2020:
        article_id = int(meta['article_id'])
        if year not in europe_ids_by_year:
            europe_ids_by_year[year] = []
        europe_ids_by_year[year].append(article_id)

# Calculate total per year
total_counts = {year: len(ids) for year, ids in sorted(europe_ids_by_year.items())}

print('__RESULT__:')
print(json.dumps({
    "total_counts": total_counts,
    "grand_total": sum(total_counts.values())
}))

