import json

# Read Europe metadata for 2010-2020
metadata_key = 'var_functions.query_db:2'
metadata_data = locals()[metadata_key]

if isinstance(metadata_data, str) and metadata_data.endswith('.json'):
    with open(metadata_data, 'r') as f:
        metadata_data = json.load(f)

# Extract article IDs and their publication years
europe_articles = []
for meta in metadata_data:
    year = int(meta['publication_date'][:4])
    if 2010 <= year <= 2020:
        europe_articles.append({
            'article_id': int(meta['article_id']),
            'year': year
        })

# Group by year
articles_by_year = {}
for article in europe_articles:
    year = article['year']
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(article['article_id'])

print('__RESULT__:')
print(json.dumps({
    'total_europe_articles': len(europe_articles),
    'yearly_counts': {year: len(ids) for year, ids in sorted(articles_by_year.items())},
    'year_range': '2010-2020',
    'num_years': len(articles_by_year)
}))

